package util

// Mensajes de error reutilizables
const (
	ErrTelefonoFormato = "El teléfono debe tener exactamente 9 dígitos numéricos"
	ErrEmailFormato    = "El email no tiene un formato válido"
	ErrFechaFormato    = "La fecha debe tener formato YYYY-MM-DD"
	ErrCampoRequerido  = "El campo es requerido"
	ErrEnumInvalido    = "Valor no permitido para el campo"
)

// Regex reutilizables
const (
	RegexTelefono = `^[0-9]{9}$`
	RegexEmail    = `^[\w\.-]+@[\w\.-]+\.[a-zA-Z]{2,}$`
)

package util

import (
	"regexp"
	"time"
)

func ValidarTelefono(telefono string) bool {
	return regexp.MustCompile(RegexTelefono).MatchString(telefono)
}

func ValidarEmail(email string) bool {
	return regexp.MustCompile(RegexEmail).MatchString(email)
}

func ValidarFecha(fecha string) bool {
	_, err := time.Parse("2006-01-02", fecha)
	return err == nil
}
